import json
from typing import Union


def flatten_ec2_metadata(
    data: Union[dict, str],
    max_depth: int = 20
) -> dict:
    """
    Convert AWS EC2 instance metadata JSON response into a flattened dictionary with dot-notation keys.

    Parameters:
        data (Union[dict, str]): Input as a pre-parsed dict or a raw JSON string.
        max_depth (int): Maximum recursion depth allowed. Defaults to 20.

    Returns:
        dict: A flat dictionary where nested keys are joined with dot-notation.

    Raises:
        ValueError: If input is None or not a dict or str type.
        ValueError: If a JSON string input cannot be parsed by json.loads().
        ValueError: If recursion depth reaches max_depth.

    Depth-limit behavior:
        Raises ValueError when depth >= max_depth, so recursion never exceeds exactly max_depth levels.

    Example:
        >>> metadata = '{"network": {"interfaces": [{"mac": "0e:49:61:0f:c3:11"}]}}'
        >>> flatten_ec2_metadata(metadata)
        {'network.interfaces.0.mac': '0e:49:61:0f:c3:11'}
    """
    if data is None or not isinstance(data, (dict, str)):
        raise ValueError(f"Input must be a dict or str, got {type(data).__name__}")

    if isinstance(data, str):
        try:
            data = json.loads(data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Failed to parse JSON string: {e}")

    if not isinstance(data, dict):
        return {"": data}

    def _flatten(obj: object, prefix: str, depth: int) -> dict:
        if depth >= max_depth:
            raise ValueError(f"Recursion depth reached max_depth={max_depth}")
        result = {}
        if isinstance(obj, dict):
            for key, value in obj.items():
                new_key = prefix + "." + key if prefix else key
                result.update(_flatten(value, new_key, depth + 1))
        elif isinstance(obj, list):
            for i, value in enumerate(obj):
                new_key = prefix + "." + str(i) if prefix else str(i)
                result.update(_flatten(value, new_key, depth + 1))
        else:
            result[prefix] = obj
        return result

    return _flatten(data, "", 0)

import re

AWS_KEY_PATTERN = re.compile(r'\b((?:AKIA|ASIA|AROA|AIDA)[A-Z0-9]{16})\b', re.ASCII)

def extract_aws_keys(text):
    return AWS_KEY_PATTERN.findall(text)

from typing import Any


def extract_dynamodb_value(typed_value: dict) -> Any:
    """
    Extract a plain Python value from a DynamoDB typed value dict.

    :param typed_value: A dict with a single DynamoDB type key (e.g., {'S': 'hello'}).
    :return: The extracted Python value.
    :raises ValueError: If the type key is unsupported.
    """
    if 'S' in typed_value:
        return typed_value['S']
    elif 'N' in typed_value:
        return float(typed_value['N'])
    elif 'BOOL' in typed_value:
        return typed_value['BOOL']
    else:
        raise ValueError(f"Unsupported DynamoDB type in: {typed_value}")


def filter_dynamodb_items(
    items: list[dict],
    attribute_name: str,
    condition_value: Any
) -> list[dict]:
    """
    Filter DynamoDB items based on a simple attribute condition.

    :param items: List of item dicts in DynamoDB boto3 typed format.
    :param attribute_name: The attribute name to filter on (non-empty string).
    :param condition_value: The plain Python value to compare against.
    :return: List of items where the attribute matches the condition value.
    :raises ValueError: If items is None, contains non-dict elements,
                        attribute_name is None/not a string/empty string,
                        or an item's attribute has an unsupported DynamoDB type.
    """
    if items is None:
        raise ValueError("items must not be None")
    if not isinstance(attribute_name, str) or attribute_name == '' or attribute_name is None:
        raise ValueError("attribute_name must be a non-empty string")
    for item in items:
        if not isinstance(item, dict):
            raise ValueError(f"All items must be dicts, got: {type(item)}")

    if isinstance(condition_value, (int, float)) and not isinstance(condition_value, bool):
        compare_value = float(condition_value)
    else:
        compare_value = condition_value

    result = []
    for item in items:
        if attribute_name not in item:
            continue
        extracted = extract_dynamodb_value(item[attribute_name])
        if isinstance(extracted, float) and isinstance(compare_value, float):
            if extracted == compare_value:
                result.append(item)
        else:
            if extracted == compare_value:
                result.append(item)
    return result
